        door_count = door_count + 1
    }
    prev_door_state = door_state
    if (door_count >= 2) {
        (#Curtain).curtain_close()
        end_time = (#Clock).clock_timestamp
        duration := end_time - start_time
        (#Alarm).alarm_strobe()
        (#Clock).clock_delay(duration * 1000)
        (#Alarm).alarm_off()
        break
    }
}"}

